import { connect } from "../database.js";

export const registrarAnotacion = async (req, res) => {
  const pool = connect();

  try {
    const {
      // ── Identificación por nombre (sin IDs) ──────────────
      nombre_estudiante,
      apellido_estudiante,
      nombre_reporta,
      apellido_reporta,
      // ── Datos del incidente ───────────────────────────────
      fecha_incidente    = null,
      tipo_falta,
      categoria          = null,
      descripcion,
      sancion            = null,
      fecha_sancion      = null,
      notificado_padres  = 0,
      fecha_notificacion = null,
      seguimiento        = null,
    } = req.body;

    // ── Validaciones ──────────────────────────────────────
    const camposObligatorios = {
      nombre_estudiante,
      apellido_estudiante,
      nombre_reporta,
      apellido_reporta,
      tipo_falta,
      descripcion,
    };

    const faltantes = Object.entries(camposObligatorios)
      .filter(([, v]) => v === undefined || v === null || v === "")
      .map(([k]) => k);

    if (faltantes.length > 0) {
      return res.status(400).json({
        ok: false,
        mensaje: `Faltan campos obligatorios: ${faltantes.join(", ")}`,
      });
    }

    const tiposValidos = ["Leve", "Moderada", "Grave", "Muy_grave"];
    if (!tiposValidos.includes(tipo_falta)) {
      return res.status(400).json({
        ok: false,
        mensaje: `Tipo de falta inválido. Valores permitidos: ${tiposValidos.join(", ")}`,
      });
    }

    // ── Llamada al procedimiento ──────────────────────────
    await pool.query(
      `CALL sp_registrar_anotacion_estudiante(
        ?, ?, ?, ?,
        ?, ?, ?, ?,
        ?, ?, ?, ?, ?,
        @id_reporte, @codigo_estudiante,
        @nombre_completo_est, @nombre_completo_rep,
        @mensaje
      )`,
      [
        nombre_estudiante,   apellido_estudiante,
        nombre_reporta,      apellido_reporta,
        fecha_incidente,     tipo_falta,          categoria,
        descripcion,         sancion,             fecha_sancion,
        notificado_padres,   fecha_notificacion,  seguimiento,
      ]
    );

    // ── Leer variables de salida ──────────────────────────
    const [[resultado]] = await pool.query(`
      SELECT
        @id_reporte            AS id_reporte,
        @codigo_estudiante     AS codigo_estudiante,
        @nombre_completo_est   AS estudiante,
        @nombre_completo_rep   AS reportado_por,
        @mensaje               AS mensaje
    `);

    if (resultado.mensaje?.startsWith("Error:")) {
      return res.status(409).json({
        ok: false,
        mensaje: resultado.mensaje,
      });
    }

    return res.status(201).json({
      ok: true,
      mensaje: resultado.mensaje,
      data: {
        id_reporte:        resultado.id_reporte,
        codigo_estudiante: resultado.codigo_estudiante,
        estudiante:        resultado.estudiante,
        reportado_por:     resultado.reportado_por,
      },
    });

  } catch (error) {
    console.error("[registrarAnotacion]", error);
    return res.status(500).json({
      ok: false,
      mensaje: "Error interno del servidor.",
      detalle: process.env.NODE_ENV === "development" ? error.message : undefined,
    });
  }
};


export const obtenerAnotaciones = async (req, res) => {
  const pool = connect();

  try {
    const [rows] = await pool.query(`
      SELECT
        rd.id                                        AS id_reporte,
        CONCAT(pe.Nombre, ' ', pe.Apellido)          AS estudiante,
        e.Codigo_estudiante                          AS codigo_estudiante,
        g.Nombre                                     AS grado,
        g.Paralelo                                   AS paralelo,
        CONCAT(pr.Nombre, ' ', pr.Apellido)          AS reportado_por,
        ro.Nombre                                    AS rol_reporta,
        rd.Fecha_incidente                           AS fecha_incidente,
        rd.Tipo_falta                                AS tipo_falta,
        rd.Categoria                                 AS categoria,
        rd.Descripcion                               AS descripcion,
        rd.Sancion                                   AS sancion,
        rd.Fecha_sancion                             AS fecha_sancion,
        rd.Notificado_padres                         AS notificado_padres,
        rd.Fecha_notificacion                        AS fecha_notificacion,
        rd.Estado                                    AS estado,
        rd.Seguimiento                               AS seguimiento,
        rd.Creado_en                                 AS fecha_registro
      FROM   reportes_disciplinarios rd
      INNER JOIN estudiante  e   ON rd.ID_Estudiante    = e.id
      INNER JOIN users       ue  ON e.ID_User           = ue.id
      INNER JOIN persona     pe  ON ue.ID_Persona       = pe.id
      INNER JOIN users       ur  ON rd.ID_Reportado_por = ur.id
      INNER JOIN persona     pr  ON ur.ID_Persona       = pr.id
      INNER JOIN roles       ro  ON ur.ID_Rol           = ro.id
      LEFT  JOIN matricula   m   ON e.id = m.ID_Estudiante
                                AND m.Estado_matricula = 'Activa'
      LEFT  JOIN grado       g   ON m.ID_Grado = g.id
      ORDER BY rd.Creado_en DESC
    `);

    return res.status(200).json({
      ok: true,
      total: rows.length,
      data: rows,
    });

  } catch (error) {
    console.error("[obtenerAnotaciones]", error);
    return res.status(500).json({
      ok: false,
      mensaje: "Error interno del servidor.",
      detalle: process.env.NODE_ENV === "development" ? error.message : undefined,
    });
  }
};


export const obtenerAnotacionesPorEstudiante = async (req, res) => {
  const pool = connect();

  try {
    const { nombre, apellido } = req.query;

    if (!nombre || !apellido) {
      return res.status(400).json({
        ok: false,
        mensaje: "Debe proporcionar nombre y apellido como query params. Ej: ?nombre=Santiago&apellido=Sánchez",
      });
    }

    const [rows] = await pool.query(
      `SELECT
        rd.id                                        AS id_reporte,
        CONCAT(pe.Nombre, ' ', pe.Apellido)          AS estudiante,
        e.Codigo_estudiante                          AS codigo_estudiante,
        g.Nombre                                     AS grado,
        rd.Fecha_incidente                           AS fecha_incidente,
        rd.Tipo_falta                                AS tipo_falta,
        rd.Categoria                                 AS categoria,
        rd.Descripcion                               AS descripcion,
        rd.Sancion                                   AS sancion,
        rd.Estado                                    AS estado,
        CONCAT(pr.Nombre, ' ', pr.Apellido)          AS reportado_por,
        rd.Creado_en                                 AS fecha_registro
      FROM   reportes_disciplinarios rd
      INNER JOIN estudiante  e  ON rd.ID_Estudiante    = e.id
      INNER JOIN users       ue ON e.ID_User           = ue.id
      INNER JOIN persona     pe ON ue.ID_Persona       = pe.id
      INNER JOIN users       ur ON rd.ID_Reportado_por = ur.id
      INNER JOIN persona     pr ON ur.ID_Persona       = pr.id
      LEFT  JOIN matricula   m  ON e.id = m.ID_Estudiante
                               AND m.Estado_matricula = 'Activa'
      LEFT  JOIN grado       g  ON m.ID_Grado = g.id
      WHERE  pe.Nombre   LIKE CONCAT('%', ?, '%')
        AND  pe.Apellido LIKE CONCAT('%', ?, '%')
      ORDER BY rd.Creado_en DESC`,
      [nombre.trim(), apellido.trim()]
    );

    if (rows.length === 0) {
      return res.status(404).json({
        ok: false,
        mensaje: `No se encontraron anotaciones para "${nombre} ${apellido}".`,
      });
    }

    return res.status(200).json({
      ok: true,
      total: rows.length,
      estudiante: rows[0].estudiante,
      codigo_estudiante: rows[0].codigo_estudiante,
      data: rows,
    });

  } catch (error) {
    console.error("[obtenerAnotacionesPorEstudiante]", error);
    return res.status(500).json({
      ok: false,
      mensaje: "Error interno del servidor.",
      detalle: process.env.NODE_ENV === "development" ? error.message : undefined,
    });
  }
};


export const actualizarEstadoAnotacion = async (req, res) => {
  const pool = connect();

  try {
    const { id } = req.params;
    const { nombre, apellido, estado, seguimiento = null } = req.body;
    const usuarioId = req.user?.id ?? 1;

    const estadosValidos = ["Abierto", "En_proceso", "Resuelto", "Cerrado"];
    if (!estado || !estadosValidos.includes(estado)) {
      return res.status(400).json({
        ok: false,
        mensaje: `Estado inválido. Valores permitidos: ${estadosValidos.join(", ")}`,
      });
    }

    // 1. Ejecutar el procedimiento
    await pool.query(
      `CALL sp_actualizar_estado_anotacion(?, ?, ?, ?, ?, ?, @id_rep, @nombre_est, @msg)`,
      [nombre, apellido, id ?? null, estado, seguimiento, usuarioId]
    );

    // 2. Leer las variables de salida en una query separada
    const [[result]] = await pool.query(
      `SELECT @id_rep AS id_reporte, @nombre_est AS estudiante, @msg AS mensaje`
    );

    const { id_reporte, estudiante, mensaje } = result;

    if (!id_reporte) {
      return res.status(404).json({ ok: false, mensaje });
    }

    return res.status(200).json({ ok: true, mensaje, id_reporte, estudiante });

  } catch (error) {
    console.error("[actualizarEstadoAnotacion]", error);
    return res.status(500).json({
      ok: false,
      mensaje: "Error interno del servidor.",
      detalle: process.env.NODE_ENV === "development" ? error.message : undefined,
    });
  }
};

